<!DOCTYPE>
<html>
<head></head>
<body>
<div class="javascript_css"></div>
<script>
function functionName() { var color = 360;
var [color0, color1, color2] = [`hsl(${color} 100% 90%)`, `hsl(${color} 100% 70%)`, `hsl(${color} 100% 50%)`];
var imgElement = document.createElement("img");
imgElement.setAttribute("id", "img0");
imgElement.setAttribute("class", "img_simple");
imgElement.style.position = "absolute";
imgElement.style.top = "60px";
imgElement.style.width = "50px";
imgElement.style.height = "50px";
imgElement.style.background = `repeating-conic-gradient(from 0deg, ${color0} 0deg 30deg, ${color1} 30deg 60deg, ${color2} 60deg 90deg)`;
imgElement.style.transition = "all 0.5s ease-out";
document.getElementsByClassName("javascript_css")[0].appendChild(imgElement);
keyframes_javascript2(document.getElementById("img0"));
}
</script>
<script>
function keyframes_javascript2(event_target) {
const keyframes = [
{ transform: "rotate(0)" },
{ transform: "rotate(360deg)" },
];
const timing = {
duration: 2000,
iterations: "Infinity",
};
event_target.animate(keyframes, timing);
}
</script>
<script>
topbar();
function topbar() {
document.getElementsByClassName("javascript_css")[0].style.position = "absolute";
document.getElementsByClassName("javascript_css")[0].style.width = "300px";
document.getElementsByClassName("javascript_css")[0].style.height = "50px";
document.getElementsByClassName("javascript_css")[0].style.border = "1px solid gray";
document.getElementsByClassName("javascript_css")[0].style.borderRadius = "2px";
document.getElementsByClassName("javascript_css")[0].innerHTML = "";
functionName();
}
</script>
</body>
</html>
